query:
-- Buscar ID do lead
SELECT @leadId := id FROM leads WHERE telefone = '11946863751' ORDER BY createdAt DESC LIMIT 1;

-- Buscar próximo corretor disponível da fila foco
SELECT @corretorId := corretorId FROM fila_distribuicao WHERE ativo = 1 AND filaFoco = 1 ORDER BY posicao LIMIT 1;

-- Se não houver corretor na fila foco, buscar da fila geral
SELECT @corretorId := COALESCE(@corretorId, (SELECT corretorId FROM fila_distribuicao WHERE ativo = 1 ORDER BY posicao LIMIT 1));

-- Atribuir lead ao corretor
UPDATE leads 
SET corretorId = @corretorId, status = 'aguardando_atendimento', dataDistribuicao = NOW()
WHERE id = @leadId;

-- Verificar distribuição
SELECT l.id, l.nome, l.telefone, l.corretorId, l.status, l.faixaRenda, u.name as corretor_nome
FROM leads l
LEFT JOIN users u ON l.corretorId = u.openId
WHERE l.id = @leadId;

